package ql.src.org.apache.hadoop.hive.ql.hooks;

public class PreExecutePrinter implements ExecuteWithHookContext { @ Override public void run ( HookContext hookContext ) throws Exception { assert ( hookContext . getHookType ( ) == HookType . PRE_EXEC_HOOK ) ; SessionState ss = SessionState . get ( ) ; Set < ReadEntity > inputs = hookContext . getInputs ( ) ; Set < WriteEntity > outputs = hookContext . getOutputs ( ) ; UserGroupInformation ugi = hookContext . getUgi ( ) ; this . run ( ss , inputs , outputs , ugi ) ; } public void run ( SessionState sess , Set < ReadEntity > inputs , Set < WriteEntity > outputs , UserGroupInformation ugi ) throws Exception { LogHelper console = SessionState . getConsole ( ) ; if ( console == null ) { return ; } if ( sess != null ) { console . printError ( "PREHOOK: query: " + sess . getCmd ( ) . trim ( ) ) ; console . printError ( "PREHOOK: type: " + sess . getCommandType ( ) ) ; } printEntities ( console , inputs , "PREHOOK: Input: " ) ; printEntities ( console , outputs , "PREHOOK: Output: " ) ; } static void printEntities ( LogHelper console , Set < ? > entities , String prefix ) { List < String > strings = new ArrayList < String > ( ) ; for ( Object o : entities ) { strings . add ( o . toString ( ) ) ; } Collections . sort ( strings ) ; for ( String s : strings ) { console . printError ( prefix + s ) ; } } }